def estimate_limits(ctx):
    """Return one bounded-action LimitEstimate per joint in ctx.joints."""
    import math
    import re

    from post_process.kinematic_solver.sdk import next_axis_from_feedback

    evidence = getattr(ctx, "evidence", {}) or {}
    joints = getattr(ctx, "joints", {}) or {}

    feedback = str(
        getattr(ctx, "last_feedback", "")
        or evidence.get("__last_feedback__", "")
        or evidence.get("last_feedback", "")
        or ""
    )
    feedback_l = feedback.lower()

    REV_10 = math.radians(10.0)
    PRI_10 = 0.010

    def norm(v):
        try:
            x, y, z = float(v[0]), float(v[1]), float(v[2])
        except Exception:
            x, y, z = 1.0, 0.0, 0.0
        n = math.sqrt(x * x + y * y + z * z)
        if n <= 1e-12:
            return [1.0, 0.0, 0.0]
        return [x / n, y / n, z / n]

    def dot(a, b):
        return float(a[0] * b[0] + a[1] * b[1] + a[2] * b[2])

    def ev_for(name):
        return evidence.get(name, {}) or {}

    def labels_for(name):
        return " ".join(str(x).lower() for x in (ev_for(name).get("labels") or []))

    def initial_for(name, joint):
        init = ev_for(name).get("initial_estimate") or {}
        return (
            norm(init.get("axis_world", joint.get("axis_world", [1.0, 0.0, 0.0]))),
            float(init.get("lower", 0.0) or 0.0),
            float(init.get("upper", 0.0) or 0.0),
        )

    def recommended_axis(name, joint):
        ev = ev_for(name)
        rec = ev.get("recommended_axis_world")
        if rec and len(rec) >= 3:
            return norm(rec)

        labels = labels_for(name)
        best_axis = None
        best_score = -1.0e100
        for cand in ev.get("axis_candidates") or []:
            aw = cand.get("axis_world")
            if not aw or len(aw) < 3:
                continue
            score = float(cand.get("score", 0.0) or 0.0)
            reason = str(cand.get("reason", "")).lower()

            if joint.get("type") == "prismatic" and any(
                k in labels for k in ("drawer", "pan", "tray", "basket", "bin", "pull-out", "pull out")
            ):
                if "outward" in reason or "centroid-outward" in reason:
                    score += 0.25
                if "authored" in reason:
                    score -= 0.05

            if score > best_score:
                best_score = score
                best_axis = aw

        return norm(best_axis if best_axis is not None else joint.get("axis_world", [1.0, 0.0, 0.0]))

    def mentioned(name):
        return name.lower() in feedback_l

    def block_for_joint(name):
        if not mentioned(name):
            return ""
        idx = feedback_l.find(("joint: " + name.lower()))
        if idx < 0:
            idx = feedback_l.find(name.lower())
        if idx < 0:
            return feedback_l
        nxt = feedback_l.find("\n[", idx + 1)
        end = nxt if nxt >= 0 else len(feedback_l)
        return feedback_l[idx:end]

    def overlap_blocked(name):
        block = block_for_joint(name)
        if not block:
            return False
        return (
            "qc_sampled_motion_overlap" in block
            or "sampled_motion_overlap" in block
            or "sampled articulation motion intersects" in block
            or "intersects parent/static geometry" in block
            or "intersects geometry" in block
        )

    def axis_blocked(name):
        block = block_for_joint(name)
        if not block:
            return False
        return (
            "qc_joint_axis" in block
            or "joint axis validation failed" in block
            or "candidate_axis_world" in block
            or "target_axis_world" in block
            or "deviates from" in block
        )

    def negative_invalid(name):
        block = block_for_joint(name)
        if not block:
            return False
        return (
            "invalid at q=-" in block
            or re.search(r"invalid\s+at\s+q\s*=\s*-", block) is not None
        )

    def endpoint_q(name, endpoint):
        if not mentioned(name):
            return None
        pat = (
            re.escape(name.lower())
            + r"\s*:\s*.{0,800}?"
            + re.escape(endpoint.lower())
            + r"\s+endpoint\s+q\s*=\s*([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)"
        )
        m = re.search(pat, feedback_l, flags=re.DOTALL)
        if not m:
            return None
        try:
            return float(m.group(1))
        except Exception:
            return None

    def target_axis_from_feedback(name):
        block = block_for_joint(name)
        if not block:
            return None
        m = re.search(
            r"target_axis_world\s*=\s*\[\s*([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)\s*,\s*"
            r"([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)\s*,\s*"
            r"([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)\s*\]",
            block,
        )
        if not m:
            return None
        try:
            return norm([float(m.group(1)), float(m.group(2)), float(m.group(3))])
        except Exception:
            return None

    def rotate_toward(current, target, max_degrees):
        current = norm(current)
        target = norm(target)
        c = max(-1.0, min(1.0, dot(current, target)))
        angle = math.acos(c)
        max_angle = math.radians(max_degrees)
        if angle <= 1e-12:
            return current
        step = min(max_angle, angle)
        rel = [
            target[0] - c * current[0],
            target[1] - c * current[1],
            target[2] - c * current[2],
        ]
        rel = norm(rel)
        return norm(
            [
                math.cos(step) * current[0] + math.sin(step) * rel[0],
                math.cos(step) * current[1] + math.sin(step) * rel[1],
                math.cos(step) * current[2] + math.sin(step) * rel[2],
            ]
        )

    estimates = []

    for name, joint in sorted(joints.items()):
        joint_type = joint.get("type")
        labels = labels_for(name)

        axis, lower, upper = initial_for(name, joint)
        axis = recommended_axis(name, joint)

        # Reconstruct the previously submitted candidate from the editable-loop
        # history. These carry-forward values are not new actions this iteration.
        if joint_type == "revolute":
            if "timer" in labels and lower < 0.0:
                lower += REV_10
            elif any(k in labels for k in ("temperature", "temp", "knob", "dial")):
                upper += REV_10
        elif joint_type == "prismatic":
            if any(k in labels for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")):
                upper = max(upper, 0.060)

        fb_lower = endpoint_q(name, "lower")
        fb_upper = endpoint_q(name, "upper")
        if fb_lower is not None:
            lower = fb_lower
        if fb_upper is not None:
            upper = fb_upper

        b_axis = axis_blocked(name)
        b_overlap = overlap_blocked(name)
        b_negative = negative_invalid(name)
        state = "need_fix" if (b_axis or b_overlap or b_negative) else "correct"

        axis_action = "unchanged"
        lower_action = "unchanged"
        upper_action = "unchanged"
        confidence = 0.84 if state == "correct" else 0.68

        if b_axis:
            axis_step = next_axis_from_feedback(feedback, name, axis, max_step_degrees=5.0)
            if axis_step is not None:
                old_axis = axis_step["current_axis"]
                axis = axis_step["next_axis"]
                source = (
                    "previous candidate_axis_world"
                    if axis_step["used_previous_candidate_axis"]
                    else "fallback current axis"
                )
                axis_action = (
                    "changed axis once by rotating %s toward feedback target_axis_world "
                    "by at most 5 degrees; old_axis=%s target=%s new_axis=%s "
                    "remaining_before=%.3fdeg remaining_after=%.3fdeg"
                    % (
                        source,
                        old_axis,
                        axis_step["target_axis"],
                        axis,
                        axis_step["remaining_degrees_before_step"],
                        axis_step["remaining_degrees_after_step"],
                    )
                )
                confidence = 0.70
            else:
                target = target_axis_from_feedback(name)
                if target is not None:
                    old_axis = axis
                    axis = rotate_toward(axis, target, 5.0)
                    axis_action = (
                        "changed axis once by rotating fallback current unit axis toward feedback "
                        "target_axis_world by at most 5 degrees; old_axis=%s target=%s new_axis=%s"
                        % (old_axis, target, axis)
                    )
                    confidence = 0.70
                else:
                    new_axis = recommended_axis(name, joint)
                    axis = new_axis
                    axis_action = "changed axis once by switching to SDK recommended_axis_world"
                    confidence = 0.69

        if joint_type == "prismatic" and b_overlap:
            upper += PRI_10
            upper_action = "changed upper once by +10 mm (+0.010 m) from the failed upper endpoint"
            confidence = min(confidence, 0.69)

        if joint_type == "revolute" and b_negative:
            lower += REV_10
            lower_action = "changed lower once by +10 degrees, expressed in radians"
            confidence = min(confidence, 0.68)

        estimates.append(
            LimitEstimate(
                joint_name=name,
                axis_world=norm(axis),
                lower=lower,
                upper=upper,
                confidence=confidence,
                reason=(
                    "State per joint: %s. Blocking signals parsed for this joint: "
                    "axis_blocked=%s, sampled_motion_overlap=%s, negative_endpoint_invalid=%s. "
                    "Parsed endpoint q from feedback: lower=%s, upper=%s. "
                    "Action this iteration: axis %s; lower %s; upper %s. "
                    "Blocking failures are authoritative and fixed before marking correct. "
                    "This iteration fixes part_00 QC_JOINT_AXIS by one bounded 5-degree "
                    "rotation toward the reported target axis, and fixes part_02 "
                    "QC_SAMPLED_MOTION_OVERLAP at upper q=0.07 by one bounded +10 mm "
                    "upper-limit extension. Joints without blocking feedback stay unchanged."
                )
                % (
                    state,
                    b_axis,
                    b_overlap,
                    b_negative,
                    fb_lower,
                    fb_upper,
                    axis_action,
                    lower_action,
                    upper_action,
                ),
            )
        )

    return estimates

